import { MOCK_LEADERBOARD } from './constants';
import { SurveyRecord } from './types';

const STORAGE_KEY_RECORDS = 'greenscore_survey_records';
const STORAGE_KEY_LEADERBOARD = 'greenscore_leaderboard';
const GOOGLE_SHEET_WEBAPP_URL: string =
  'https://script.google.com/macros/s/AKfycbzc35UUU9c7ZdrVKfXJB6cl6c7t6c2-aqGcd-a80ir9BE6hhn0Z0XRYTfkeF3Ab-5NrXQ/exec';

const EXPORT_SCRIPT_URL = 'https://script.google.com/macros/s/AKfycbzhYWWRq3NNco6cEex_obqvFU2kzWmodrEKQFAfQYNniIp08LZ58u2JnpUcMIHt1Mva8A/exec';

const postToSheet = async (payload: object): Promise<void> => {
  if (!GOOGLE_SHEET_WEBAPP_URL) return;
  try {
    await fetch(GOOGLE_SHEET_WEBAPP_URL, {
      method: 'POST',
      mode: 'no-cors',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify(payload),
    });
  } catch (err) {
    console.error('[dataService] Lỗi gửi Google Sheet:', err);
  }
};

export const markSurveyStart = (key: string) => {
  localStorage.setItem(key, new Date().toISOString());
};

export const getSurveyStart = (key: string): string | null => {
  return localStorage.getItem(key);
};

const EMBEDDED_B64 = "";

const decodeEmbeddedData = (): Promise<Record<string, { headers: string[]; rows: any[][] }>> => {
  return new Promise((resolve, reject) => {
    try {
      const bin = atob(EMBEDDED_B64);
      const bytes = Uint8Array.from(bin, c => c.charCodeAt(0));
      const ds = new (window as any).DecompressionStream('gzip');
      const writer = ds.writable.getWriter();
      writer.write(bytes);
      writer.close();
      new Response(ds.readable).text().then(json => resolve(JSON.parse(json))).catch(reject);
    } catch (e) {
      reject(e);
    }
  });
};

export const dataService = {

  logSurvey1Response: async (
    userEmail: string,
    questionId: string,
    value: string,
    isLast = false
  ): Promise<void> => {
    const startTime = localStorage.getItem('tn_nc1_start') || undefined;
    const endTime   = isLast ? new Date().toISOString() : undefined;
    console.log(`[NC1] ${questionId}: ${value}`);
    await postToSheet({
      type: 'nghien_cuu_1', timestamp: new Date().toISOString(),
      userEmail, questionId, value,
      ...(startTime && { nc1_startTime: startTime }),
      ...(endTime   && { nc1_endTime: endTime }),
    });
  },

  logSimulationOrder: async (
    userEmail: string, productId: string, productName: string,
    isGreenProduct: number, logisticsType: string, isGreenLogistics: number,
    packagingType: string, isGreenPackaging: number
  ): Promise<void> => {
    const productGroup: Record<string, string> = {
      '1a': '1: Bình nước - a: Xanh', '1b': '1: Bình nước - b: Thường',
      '2a': '2: Sổ tay - a: Xanh',   '2b': '2: Sổ tay - b: Thường',
      '3a': '3: Túi - a: Xanh',       '3b': '3: Túi - b: Thường',
    };
    const logisticsLabel: Record<string, string> = {
      green: 'Vận chuyển xanh', standard: 'Giao hàng tiêu chuẩn', fast: 'Giao hàng hỏa tốc',
    };
    const packagingLabel: Record<string, string> = {
      green: 'Bao bì xanh', standard: 'Đóng gói tiêu chuẩn',
    };
    await postToSheet({
      type: 'mo_phong', timestamp: new Date().toISOString(),
      userEmail, productName,
      productGroup: productGroup[productId] ?? productId,
      isGreenProduct,
      logisticsLabel: logisticsLabel[logisticsType] ?? logisticsType,
      isGreenLogistics,
      packagingLabel: packagingLabel[packagingType] ?? packagingType,
      isGreenPackaging,
    });
  },

  logSurvey2Response: async (
    userEmail: string, questionId: string, value: string, isLast = false
  ): Promise<void> => {
    const startTime = localStorage.getItem('tn_nc2_start') || undefined;
    const endTime   = isLast ? new Date().toISOString() : undefined;
    console.log(`[NC2] ${questionId}: ${value}`);
    await postToSheet({
      type: 'nghien_cuu_2', timestamp: new Date().toISOString(),
      userEmail, questionId, value,
      ...(startTime && { nc2_startTime: startTime }),
      ...(endTime   && { nc2_endTime: endTime }),
    });
  },

  saveChoice: async (record: SurveyRecord, finalScore: number): Promise<void> => {
    const existing = JSON.parse(localStorage.getItem(STORAGE_KEY_RECORDS) || '[]');
    existing.push({ ...record, timestamp: new Date().toISOString(), finalScore });
    localStorage.setItem(STORAGE_KEY_RECORDS, JSON.stringify(existing));
    dataService.updateGlobalLeaderboard(record.userEmail, finalScore);
  },

  updateGlobalLeaderboard: (email: string, score: number): void => {
    let leaderboard = JSON.parse(
      localStorage.getItem(STORAGE_KEY_LEADERBOARD) || JSON.stringify(MOCK_LEADERBOARD)
    );
    const idx = leaderboard.findIndex((u: any) => u.name === email);
    if (idx > -1) {
      if (score > leaderboard[idx].score) leaderboard[idx].score = score;
    } else {
      leaderboard.push({
        id: `user_${Date.now()}`,
        name: email,
        score,
        avatar: `https://ui-avatars.com/api/?name=${encodeURIComponent(email)}&background=random`,
      });
    }
    leaderboard.sort((a: any, b: any) => b.score - a.score);
    localStorage.setItem(STORAGE_KEY_LEADERBOARD, JSON.stringify(leaderboard));
  },

  getLeaderboard: () => {
    return JSON.parse(
      localStorage.getItem(STORAGE_KEY_LEADERBOARD) || JSON.stringify(MOCK_LEADERBOARD)
    );
  },

  // Ghi dữ liệu từng chunk rồi trả về sheet URL để redirect
  exportToGoogleSheets: async (
    onProgress: (msg: string) => void
  ): Promise<string> => {
    onProgress('Đang giải nén dữ liệu...');
    const data = await decodeEmbeddedData();

    const sheetNames = ['Nghiên cứu 1', 'Mô phỏng', 'Nghiên cứu 2'];
    const CHUNK = 200;
    let sheetUrl = '';

    for (const sheetName of sheetNames) {
      const sheet = data[sheetName];
      if (!sheet) continue;

      const allRows = [sheet.headers, ...sheet.rows];
      const totalChunks = Math.ceil(allRows.length / CHUNK);

      for (let i = 0; i < totalChunks; i++) {
        const chunk = allRows.slice(i * CHUNK, (i + 1) * CHUNK);
        onProgress(`[${sheetName}] Đang ghi ${i + 1}/${totalChunks}...`);

        const res = await fetch(EXPORT_SCRIPT_URL, {
          method: 'POST',
          headers: { 'Content-Type': 'text/plain' },
          body: JSON.stringify({
            type: 'export_data',
            sheetName,
            chunkIndex: i,
            isFirst: i === 0,
            isLastChunkOfLastSheet: sheetName === 'Nghiên cứu 2' && i === totalChunks - 1,
            rows: chunk,
          }),
        });

        const json = await res.json();
        if (json.sheetUrl) sheetUrl = json.sheetUrl;

        await new Promise(r => setTimeout(r, 300));
      }
    }

    return sheetUrl;
  },

  exportData: (): void => {
    const data = localStorage.getItem(STORAGE_KEY_RECORDS);
    if (!data) return;
    const blob = new Blob([data], { type: 'application/json' });
    const url = URL.createObjectURL(blob);
    const link = document.createElement('a');
    link.href = url;
    link.download = `survey_data_${new Date().toISOString()}.json`;
    link.click();
  },
};
